import { createTRPCClient, httpSubscriptionLink } from '@trpc/client';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import type { AppRouter } from './server';

const client = createTRPCClient<AppRouter>({
  links: [
    httpSubscriptionLink({
      url: 'http://localhost:3000',
    }),
  ],
});

async function main() {
  const values: number[] = [];

  await new Promise<void>((resolve, reject) => {
    client.countdown.subscribe(3, {
      onStarted: () => {
        console.log('subscription started');
      },
      onData: (data: any) => {
        console.log('data received:', data);
        const value = typeof data === 'number' ? data : data?.data ?? data;
        values.push(value);
      },
      onComplete: () => {
        console.log('subscription complete');
        resolve();
      },
      onError: (err: any) => {
        console.error('subscription error:', err);
        if (err && err.cause) {
          console.error('cause:', err.cause);
          if (err.cause.error) {
            console.error('cause.error:', err.cause.error);
          }
          if (err.cause.errors) {
            console.error('cause.errors:', err.cause.errors);
          }
          if (err.cause.suppressed) {
            console.error('cause.suppressed:', err.cause.suppressed);
          }
        }
        reject(err);
      },
      onStopped: () => {
        console.log('subscription stopped');
      },
    });
  });

  const here = path.dirname(fileURLToPath(import.meta.url));
  const outputPath = path.join(here, 'output.json');
  fs.writeFileSync(outputPath, JSON.stringify(values));
  console.log('Wrote output:', values);
}

main().then(() => process.exit(0)).catch((err) => {
  console.error('main failed:', err);
  process.exit(1);
});

